1	import { useEffect, useMemo, useState } from "react";
2	import ReactMarkdown from "react-markdown";
3	import remarkGfm from "remark-gfm";
4	import {
5	  fetchIncremental,
6	  runSimIngestStream,
7	  type SimDay,
8	  type SimIngestResponse,
9	  type SimItem,
10	  type SimStageEvent,
11	} from "../api";
12	import { cn } from "../lib/cn";
13	
14	type Kind = "email" | "invoice" | "bank";
15	type Mode = "isolated" | "live";
16	
17	type StageState = "pending" | "active" | "done" | "error" | "skipped";
18	
19	type StageNode = {
20	  key: string;
21	  label: string;
22	  icon: (cls?: string) => React.ReactNode;
23	  hint: string;
24	};
25	
26	const ICON_CLASS = "h-3.5 w-3.5";
27	
28	function Icon({ d, cls }: { d: string; cls?: string }) {
29	  return (
30	    <svg
31	      viewBox="0 0 24 24"
32	      fill="none"
33	      stroke="currentColor"
34	      strokeWidth="1.8"
35	      strokeLinecap="round"
36	      strokeLinejoin="round"
37	      className={cn(ICON_CLASS, cls)}
38	    >
39	      {d.split("|").map((path, i) => (
40	        <path key={i} d={path} />
41	      ))}
42	    </svg>
43	  );
44	}
45	
46	const PIPELINE: StageNode[] = [
47	  {
48	    key: "normalize",
49	    label: "normalize",
50	    hint: "Convert raw input → markdown",
51	    icon: (cls) => <Icon cls={cls} d="M7 4h10v16H7z|M9 8h6|M9 12h6|M9 16h4" />,
52	  },
53	  {
54	    key: "enrich",
55	    label: "enrich",
56	    hint: "Tavily fetch public URLs found in body",
57	    icon: (cls) => (
58	      <Icon
59	        cls={cls}
60	        d="M12 2a10 10 0 100 20 10 10 0 000-20z|M2 12h20|M12 2a15 15 0 010 20|M12 2a15 15 0 000 20"
61	      />
62	    ),
63	  },
64	  {
65	    key: "classify",
66	    label: "classify",
67	    hint: "Signal? category + priority",
68	    icon: (cls) => (
69	      <Icon cls={cls} d="M3 7l9-4 9 4-9 4-9-4z|M3 12l9 4 9-4|M3 17l9 4 9-4" />
70	    ),
71	  },
72	  {
73	    key: "resolve",
74	    label: "resolve",
75	    hint: "Link entities from stammdaten",
76	    icon: (cls) => (
77	      <Icon
78	        cls={cls}
79	        d="M10 14a4 4 0 010-5.66l3-3a4 4 0 015.66 5.66l-1.5 1.5|M14 10a4 4 0 010 5.66l-3 3a4 4 0 01-5.66-5.66l1.5-1.5"
80	      />
81	    ),
82	  },
83	  {
84	    key: "locate",
85	    label: "locate",
86	    hint: "Vector search wiki sections",
87	    icon: (cls) => (
88	      <Icon
89	        cls={cls}
90	        d="M12 2v3|M12 19v3|M2 12h3|M19 12h3|M12 7a5 5 0 100 10 5 5 0 000-10z|M12 12h.01"
91	      />
92	    ),
93	  },
94	  {
95	    key: "extract",
96	    label: "extract",
97	    hint: "LLM → patch plan ops",
98	    icon: (cls) => (
99	      <Icon cls={cls} d="M4 4l8 8|M4 20l8-8|M14 7l6 5-6 5|M14 7v10" />
100	    ),
101	  },
102	  {
103	    key: "patch",
104	    label: "patch",
105	    hint: "Apply ops to wiki files",
106	    icon: (cls) => (
107	      <Icon
108	        cls={cls}
109	        d="M12 20h9|M16.5 3.5a2.12 2.12 0 113 3L7 19l-4 1 1-4 12.5-12.5z"
110	      />
111	    ),
112	  },
113	  {
114	    key: "index",
115	    label: "index",
116	    hint: "Regenerate property index.md",
117	    icon: (cls) => <Icon cls={cls} d="M4 6h16|M4 12h16|M4 18h10|M20 18h.01" />,
118	  },
119	  {
120	    key: "reindex",
121	    label: "reindex",
122	    hint: "Refresh wiki vector chunks",
123	    icon: (cls) => <Icon cls={cls} d="M21 12a9 9 0 11-3-6.7|M21 4v5h-5" />,
124	  },
125	];
126	
127	type ToolCall = {
128	  tool: string;
129	  status: "start" | "ok" | "fail";
130	  url?: string;
131	  ms?: number;
132	  chars?: number;
133	  ts: number | null;
134	  meta: Record<string, unknown>;
135	};
136	
137	type StageRecord = {
138	  state: StageState;
139	  data: Record<string, unknown> | null;
140	  startedAt: number | null;
141	  endedAt: number | null;
142	  toolCalls: ToolCall[];
143	};
144	
145	function emptyStages(): Record<string, StageRecord> {
146	  const out: Record<string, StageRecord> = {};
147	  for (const n of PIPELINE) {
148	    out[n.key] = {
149	      state: "pending",
150	      data: null,
151	      startedAt: null,
152	      endedAt: null,
153	      toolCalls: [],
154	    };
155	  }
156	  return out;
157	}
158	
159	const KIND_LABELS: Record<Kind, string> = {
160	  email: "Emails",
161	  invoice: "Invoices",
162	  bank: "Bank tx",
163	};
164	
165	export function IngestPage() {
166	  const [days, setDays] = useState<SimDay[] | null>(null);
167	  const [error, setError] = useState<string | null>(null);
168	  const [day, setDay] = useState<number | null>(null);
169	  const [kind, setKind] = useState<Kind>("email");
170	  const [itemId, setItemId] = useState<string | null>(null);
171	  const [mode, setMode] = useState<Mode>("isolated");
172	  const [running, setRunning] = useState(false);
173	  const [result, setResult] = useState<SimIngestResponse | null>(null);
174	  const [activeFile, setActiveFile] = useState<string | null>(null);
175	  const [events, setEvents] = useState<SimStageEvent[]>([]);
176	  const [cursor, setCursor] = useState<number>(-1);
177	  const [followLive, setFollowLive] = useState(true);
178	  const [tab, setTab] = useState<"flow" | "files">("flow");
179	
180	  useEffect(() => {
181	    if (result) setTab("files");
182	  }, [result]);
183	
184	  useEffect(() => {
185	    fetchIncremental()
186	      .then((d) => {
187	        setDays(d);
188	        if (d.length > 0) setDay(d[d.length - 1].day);
189	      })
190	      .catch((e) => setError(String(e)));
191	  }, []);
192	
193	  const currentDay = useMemo(
194	    () => days?.find((d) => d.day === day) ?? null,
195	    [days, day],
196	  );
197	
198	  const items: SimItem[] = useMemo(() => {
199	    if (!currentDay) return [];
200	    if (kind === "email") return currentDay.emails;
201	    if (kind === "invoice") return currentDay.invoices;
202	    return currentDay.bank;
203	  }, [currentDay, kind]);
204	
205	  useEffect(() => {
206	    if (items.length === 0) {
207	      setItemId(null);
208	      return;
209	    }
210	    if (!itemId || !items.some((i) => i.id === itemId)) {
211	      setItemId(items[0].id);
212	    }
213	  }, [items, itemId]);
214	
215	  useEffect(() => {
216	    if (!result) {
217	      setActiveFile(null);
218	      return;
219	    }
220	    setActiveFile(result.files[0]?.path ?? null);
221	  }, [result]);
222	
223	  function handleStage(ev: SimStageEvent) {
224	    setEvents((prev) => {
225	      const enriched: SimStageEvent = {
226	        ...ev,
227	        data: { ...ev.data, _recvAt: performance.now() },
228	      };
229	      const next = [...prev, enriched];
230	      if (followLive) setCursor(next.length - 1);
231	      return next;
232	    });
233	  }
234	
235	  async function handleRun() {
236	    if (!day || !itemId) return;
237	    setRunning(true);
238	    setError(null);
239	    setResult(null);
240	    setEvents([]);
241	    setCursor(-1);
242	    setFollowLive(true);
243	    try {
244	      await runSimIngestStream(
245	        { day, kind, id: itemId, mode },
246	        {
247	          onStage: handleStage,
248	          onResponse: (resp) => setResult(resp),
249	          onError: (err) => setError(`${err.status}: ${err.detail}`),
250	        },
251	      );
252	    } catch (e) {
253	      setError(String(e));
254	    } finally {
255	      setRunning(false);
256	    }
257	  }
258	
259	  return (
260	    <div className="flex h-screen flex-col bg-[var(--color-bg)] text-[var(--color-fg)]">
261	      <header className="glass flex h-12 shrink-0 items-center gap-3 border-b border-[var(--color-border)] px-4">
262	        <a
263	          href="/"
264	          className="font-display text-[12px] font-medium text-[var(--color-ink-50)] hover:text-[var(--color-accent)]"
265	        >
266	          ← PropContext Wiki
267	        </a>
268	        <span className="text-[12.5px] uppercase tracking-[0.18em] text-[var(--color-fg-muted)]">
269	          Simulate ingest
270	        </span>
271	      </header>
272	
273	      <div className="flex min-h-0 flex-1">
274	        <aside className="flex w-[360px] shrink-0 flex-col border-r border-[var(--color-border)] bg-[var(--color-bg)]/40">
275	          <div className="border-b border-[var(--color-border)] px-3 py-3">
276	            <Field label="Day">
277	              <select
