621	type DiffLine = { kind: "add" | "del" | "ctx"; text: string };
622	
623	function diffLines(a: string, b: string): DiffLine[] {
624	  if (a === b) return a.split("\n").map((text) => ({ kind: "ctx", text }));
625	  const al = a === "" ? [] : a.split("\n");
626	  const bl = b === "" ? [] : b.split("\n");
627	  const m = al.length;
628	  const n = bl.length;
629	  const dp: number[][] = Array.from({ length: m + 1 }, () =>
630	    new Array(n + 1).fill(0),
631	  );
632	  for (let i = m - 1; i >= 0; i--) {
633	    for (let j = n - 1; j >= 0; j--) {
634	      dp[i][j] =
635	        al[i] === bl[j]
636	          ? dp[i + 1][j + 1] + 1
637	          : Math.max(dp[i + 1][j], dp[i][j + 1]);
638	    }
639	  }
640	  const out: DiffLine[] = [];
641	  let i = 0;
642	  let j = 0;
643	  while (i < m && j < n) {
644	    if (al[i] === bl[j]) {
645	      out.push({ kind: "ctx", text: al[i] });
646	      i++;
647	      j++;
648	    } else if (dp[i + 1][j] >= dp[i][j + 1]) {
649	      out.push({ kind: "del", text: al[i] });
650	      i++;
651	    } else {
652	      out.push({ kind: "add", text: bl[j] });
653	      j++;
654	    }
655	  }
656	  while (i < m) out.push({ kind: "del", text: al[i++] });
657	  while (j < n) out.push({ kind: "add", text: bl[j++] });
658	  return out;
659	}
