661	function quickDiffStats(
662	  a: string,
663	  b: string,
664	): { added: number; removed: number } {
665	  if (a === b) return { added: 0, removed: 0 };
666	  if (a === "") return { added: b.split("\n").length, removed: 0 };
667	  if (b === "") return { added: 0, removed: a.split("\n").length };
668	  const lines = diffLines(a, b);
669	  return {
670	    added: lines.filter((l) => l.kind === "add").length,
671	    removed: lines.filter((l) => l.kind === "del").length,
672	  };
673	}
