747	type DerivedView = {
748	  stages: Record<string, StageRecord>;
749	  activeStage: string | null;
750	  terminalStatus: "applied" | "no_signal" | null;
751	  currentEvent: SimStageEvent | null;
752	};
753	
754	function deriveFromEvents(events: SimStageEvent[], upto: number): DerivedView {
755	  const stages = emptyStages();
756	  let activeStage: string | null = null;
757	  let terminalStatus: "applied" | "no_signal" | null = null;
758	  const slice = upto < 0 ? [] : events.slice(0, upto + 1);
759	  for (const ev of slice) {
760	    const raw = ev.stage;
761	    if (raw === "done") {
762	      terminalStatus = (ev.data?.status as "applied" | "no_signal") ?? null;
763	      activeStage = null;
764	      if (terminalStatus === "no_signal") {
765	        for (const n of PIPELINE) {
766	          if (
767	            n.key !== "normalize" &&
768	            n.key !== "classify" &&
769	            stages[n.key].state === "pending"
770	          ) {
771	            stages[n.key] = { ...stages[n.key], state: "skipped" };
772	          }
773	        }
774	      }
775	      continue;
776	    }
777	    const isToolEvent = raw.includes(".tool") && !raw.endsWith(".done");
778	    if (isToolEvent) {
779	      const parentKey = raw.split(".tool", 1)[0];
780	      if (!PIPELINE.some((n) => n.key === parentKey)) continue;
781	      const cur = stages[parentKey];
782	      const data = ev.data as Record<string, unknown>;
783	      const tsRaw = data._recvAt;
784	      const ts = typeof tsRaw === "number" ? tsRaw : null;
785	      const status = (data.status as ToolCall["status"]) ?? "ok";
786	      const next: ToolCall[] = [...cur.toolCalls];
787	      const existingIdx =
788	        status !== "start"
789	          ? next.findIndex(
790	              (t) =>
791	                t.tool === data.tool &&
792	                t.url === data.url &&
793	                t.status === "start",
794	            )
795	          : -1;
796	      const call: ToolCall = {
797	        tool: String(data.tool ?? "tool"),
798	        status,
799	        url: typeof data.url === "string" ? data.url : undefined,
800	        ms: typeof data.ms === "number" ? data.ms : undefined,
801	        chars: typeof data.chars === "number" ? data.chars : undefined,
802	        ts,
803	        meta: data,
804	      };
805	      if (existingIdx >= 0) next[existingIdx] = call;
806	      else next.push(call);
807	      stages[parentKey] = { ...cur, toolCalls: next };
808	      continue;
809	    }
810	    const isDone = raw.endsWith(".done");
811	    const key = isDone ? raw.slice(0, -5) : raw;
812	    if (!PIPELINE.some((n) => n.key === key)) continue;
813	    const cur = stages[key];
814	    const { _recvAt, ...visibleData } = ev.data as Record<string, unknown>;
815	    const ts = typeof _recvAt === "number" ? _recvAt : null;
816	    if (isDone) {
817	      stages[key] = {
818	        ...cur,
819	        state: "done",
820	        data: visibleData,
821	        endedAt: ts,
822	      };
823	      if (activeStage === key) activeStage = null;
824	    } else {
825	      stages[key] = {
826	        ...cur,
827	        state: "active",
828	        startedAt: ts,
829	      };
830	      activeStage = key;
831	    }
832	  }
833	  const currentEvent = upto >= 0 && upto < events.length ? events[upto] : null;
834	  return { stages, activeStage, terminalStatus, currentEvent };
835	}
836	
837	function PipelineView({
838	  events,
839	  cursor,
840	  followLive,
841	  running,
842	  compact,
843	  onCursor,
844	  onFollowLive,
845	}: {
846	  events: SimStageEvent[];
847	  cursor: number;
848	  followLive: boolean;
