850	  compact: boolean;
851	  onCursor: (idx: number) => void;
852	  onFollowLive: () => void;
853	}) {
854	  const { stages, activeStage, terminalStatus, currentEvent } = useMemo(
855	    () => deriveFromEvents(events, cursor),
856	    [events, cursor],
857	  );
858	  const total = events.length;
859	  const idx = cursor < 0 ? 0 : cursor + 1;
860	  return (
861	    <div
862	      className={cn("flex flex-col", compact ? "shrink-0" : "min-h-0 flex-1")}
863	    >
864	      <div className="border-b border-[var(--color-border)] px-4 py-3">
865	        <div className="mb-2 flex items-center justify-between">
866	          <div className="flex items-center gap-2">
867	            <span className="font-mono text-[11px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
868	              Pipeline
869	            </span>
870	            {currentEvent && (
871	              <span className="font-mono text-[11px] text-[var(--color-fg-muted)]">
872	                · {currentEvent.stage}
873	              </span>
874	            )}
875	          </div>
876	          <span
877	            className={cn(
878	              "font-mono text-[11px] uppercase tracking-[0.18em]",
879	              terminalStatus === "applied" && "text-[var(--color-accent)]",
880	              terminalStatus === "no_signal" && "text-[var(--color-fg-muted)]",
881	              !terminalStatus && running && "text-[var(--color-accent)]",
882	            )}
883	          >
884	            {terminalStatus
885	              ? terminalStatus.replace("_", " ")
886	              : running
887	                ? "running"
888	                : "idle"}
889	          </span>
890	        </div>
891	        <div className="flex flex-wrap items-stretch gap-1">
892	          {PIPELINE.map((node, i) => {
893	            const rec = stages[node.key];
894	            return (
895	              <div key={node.key} className="flex items-stretch">
896	                <StageChip
897	                  node={node}
898	                  state={rec.state}
899	                  active={activeStage === node.key}
900	                  data={rec.data}
901	                  duration={
902	                    rec.startedAt && rec.endedAt
903	                      ? rec.endedAt - rec.startedAt
904	                      : null
905	                  }
906	                  onClick={() => {
907	                    const target = lastEventIndexFor(events, node.key);
908	                    if (target >= 0) onCursor(target);
909	                  }}
910	                />
911	                {i < PIPELINE.length - 1 && <Connector />}
912	              </div>
913	            );
914	          })}
915	        </div>
916	        <div className="mt-3 flex items-center gap-2">
917	          <button
918	            onClick={() => onCursor(Math.max(0, cursor - 1))}
919	            disabled={cursor <= 0}
920	            className="rounded border border-[var(--color-border-2)] bg-[var(--color-bg)] px-2 py-1 font-mono text-[11px] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)] disabled:opacity-30"
921	            title="prev event"
922	          >
923	            ◀ prev
924	          </button>
925	          <input
926	            type="range"
927	            min={0}
928	            max={Math.max(0, total - 1)}
929	            value={cursor < 0 ? 0 : cursor}
930	            disabled={total === 0}
931	            onChange={(e) => onCursor(Number(e.target.value))}
932	            className="flex-1 accent-[var(--color-accent)]"
933	          />
934	          <button
935	            onClick={() => onCursor(Math.min(total - 1, cursor + 1))}
936	            disabled={cursor >= total - 1 || total === 0}
937	            className="rounded border border-[var(--color-border-2)] bg-[var(--color-bg)] px-2 py-1 font-mono text-[11px] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)] disabled:opacity-30"
938	            title="next event"
939	          >
940	            next ▶
941	          </button>
942	          <button
943	            onClick={onFollowLive}
944	            disabled={followLive || total === 0}
945	            className={cn(
946	              "rounded border px-2 py-1 font-mono text-[11px] uppercase tracking-wide transition-colors",
947	              followLive
948	                ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
949	                : "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)]",
950	            )}
951	            title="snap to latest event"
952	          >
953	            live
954	          </button>
955	          <span className="ml-1 font-mono text-[11px] text-[var(--color-fg-muted)]">
956	            {idx} / {total}
957	          </span>
958	        </div>
959	        {currentEvent && (
960	          <div className="mt-2 font-mono text-[11px] text-[var(--color-fg-muted)]">
961	            {hintFor(currentEvent.stage)}
962	          </div>
963	        )}
964	      </div>
965	      {!compact && (
966	        <div className="grid min-h-0 flex-1 grid-cols-2 gap-3 overflow-auto px-4 py-3">
967	          {PIPELINE.filter(
968	            (n) =>
969	              stages[n.key].data ||
970	              stages[n.key].state === "active" ||
971	              stages[n.key].toolCalls.length > 0,
972	          ).map((n) => (
973	            <StagePanel key={n.key} node={n} record={stages[n.key]} />
974	          ))}
975	          {Object.values(stages).every(
976	            (s) => s.state === "pending" || s.state === "active",
977	          ) &&
978	            running && (
979	              <div className="col-span-2 text-[12.5px] text-[var(--color-fg-muted)]">
980	                waiting for first stage…
981	              </div>
982	            )}
983	        </div>
984	      )}
985	    </div>
986	  );
987	}
988	
989	function lastEventIndexFor(events: SimStageEvent[], key: string): number {
990	  for (let i = events.length - 1; i >= 0; i--) {
991	    const raw = events[i].stage;
992	    const k = raw.endsWith(".done") ? raw.slice(0, -5) : raw;
993	    if (k === key) return i;
994	  }
995	  return -1;
996	}
997	
998	function hintFor(stage: string): string {
999	  if (stage === "done") return "Pipeline finished.";
1000	  const isDone = stage.endsWith(".done");
1001	  const key = isDone ? stage.slice(0, -5) : stage;
1002	  const node = PIPELINE.find((n) => n.key === key);
1003	  if (!node) return stage;
1004	  return isDone
1005	    ? `${node.label} → done. ${node.hint}`
1006	    : `${node.label} → ${node.hint}`;
1007	}
1008	
1009	function StageChip({
1010	  node,
1011	  state,
1012	  active,
1013	  data,
1014	  duration,
1015	  onClick,
1016	}: {
1017	  node: StageNode;
1018	  state: StageState;
1019	  active: boolean;
1020	  data: Record<string, unknown> | null;
1021	  duration: number | null;
1022	  onClick: () => void;
1023	}) {
1024	  const bgClass =
1025	    state === "done"
1026	      ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
1027	      : state === "active" || active
1028	        ? "border-[var(--color-accent)] bg-[var(--color-accent)]/15 text-[var(--color-accent)] animate-pulse"
1029	        : state === "error"
1030	          ? "border-red-500/50 bg-red-500/10 text-red-400"
1031	          : state === "skipped"
1032	            ? "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-dim)] opacity-60"
1033	            : "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-muted)]";
1034	  const indicator =
1035	    state === "done"
1036	      ? "✓"
1037	      : state === "active" || active
1038	        ? "●"
1039	        : state === "error"
1040	          ? "✕"
1041	          : state === "skipped"
1042	            ? "—"
1043	            : "○";
1044	  const summary = chipSummary(node.label, data);
1045	  return (
1046	    <button
1047	      type="button"
1048	      onClick={onClick}
1049	      className={cn(
1050	        "flex min-w-[120px] flex-col rounded-md border px-2 py-1.5 text-left font-mono text-[11px] transition-colors hover:brightness-110",
1051	        bgClass,
1052	      )}
1053	      title={`${node.hint}${data ? `\n\n${JSON.stringify(data, null, 2)}` : ""}`}
1054	    >
1055	      <div className="flex items-center gap-1.5">
1056	        <span className="text-[10px]">{indicator}</span>
1057	        {node.icon()}
1058	        <span className="font-medium uppercase tracking-wide">
1059	          {node.label}
1060	        </span>
1061	      </div>
1062	      {summary && (
1063	        <span className="mt-0.5 truncate text-[10.5px] opacity-80">
1064	          {summary}
1065	        </span>
1066	      )}
1067	      {duration !== null && (
1068	        <span className="text-[9.5px] opacity-60">
1069	          {Math.round(duration)}ms
1070	        </span>
1071	      )}
1072	    </button>
1073	  );
1074	}
1075	
1076	function Connector() {
1077	  return (
1078	    <div className="flex items-center px-0.5 text-[var(--color-border-2)]">
1079	      <span className="font-mono text-[12px]">→</span>
1080	    </div>
1081	  );
1082	}
1083	
1084	function chipSummary(
1085	  label: string,
1086	  data: Record<string, unknown> | null,
1087	): string | null {
1088	  if (!data) return null;
1089	  if (label === "classify") {
1090	    const cat = data.category as string | undefined;
1091	    const conf = data.confidence as number | undefined;
1092	    if (cat) return `${cat} ${conf != null ? `· ${conf}` : ""}`.trim();
1093	  }
1094	  if (label === "extract") {
1095	    const ops = data.ops as number | undefined;
1096	    if (typeof ops === "number") return `${ops} ops`;
1097	  }
1098	  if (label === "patch") {
1099	    const ops = data.applied_ops as number | undefined;
1100	    if (typeof ops === "number") return `${ops} writes`;
1101	  }
1102	  if (label === "resolve") {
1103	    const ids = data.entity_ids as string[] | undefined;
1104	    if (ids && ids.length) return ids.slice(0, 2).join(", ");
1105	  }
1106	  if (label === "locate") {
1107	    const sec = data.sections as string[] | undefined;
1108	    if (sec && sec.length) return `${sec.length} sections`;
1109	  }
1110	  if (label === "normalize") {
1111	    const chars = data.chars as number | undefined;
1112	    if (typeof chars === "number") return `${chars} chars`;
1113	  }
1114	  if (label === "enrich") {
1115	    const fetched = (data.fetched as unknown[] | undefined)?.length ?? 0;
1116	    const skipped = (data.skipped as unknown[] | undefined)?.length ?? 0;
1117	    if (fetched || skipped) return `${fetched} fetched · ${skipped} skipped`;
1118	  }
1119	  if (label === "reindex") {
1120	    const c = data.count as number | undefined;
1121	    if (typeof c === "number") return `${c} files`;
1122	  }
1123	  return null;
1124	}
1125	
1126	function StagePanel({
1127	  node,
1128	  record,
1129	}: {
1130	  node: StageNode;
1131	  record: StageRecord;
1132	}) {
1133	  if (
1134	    !record.data &&
1135	    record.state !== "active" &&
1136	    record.toolCalls.length === 0
1137	  )
1138	    return null;
1139	  return (
1140	    <div className="rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)]/40 p-2">
1141	      <div className="mb-1 flex items-center justify-between font-mono text-[11px] uppercase tracking-[0.18em] text-[var(--color-fg-dim)]">
1142	        <span className="flex items-center gap-1.5">
1143	          {node.icon()}
1144	          {node.label}
1145	        </span>
1146	        <span
1147	          className={cn(
1148	            record.state === "done" && "text-[var(--color-accent)]",
1149	            record.state === "active" && "text-[var(--color-accent)]",
1150	          )}
1151	        >
1152	          {record.state}
1153	        </span>
1154	      </div>
1155	      {record.toolCalls.length > 0 && (
1156	        <div className="mb-2 space-y-1">
1157	          <div className="font-mono text-[10px] uppercase tracking-wide text-[var(--color-fg-dim)]">
1158	            tool calls ({record.toolCalls.length})
1159	          </div>
1160	          {record.toolCalls.map((t, i) => (
1161	            <ToolCallRow key={`${t.tool}:${t.url ?? i}:${i}`} call={t} />
1162	          ))}
1163	        </div>
1164	      )}
1165	      {record.data ? (
1166	        <pre className="max-h-[220px] overflow-auto whitespace-pre-wrap break-all font-mono text-[11px] leading-snug text-[var(--color-fg-muted)]">
1167	          {JSON.stringify(record.data, null, 2)}
1168	        </pre>
1169	      ) : record.toolCalls.length === 0 ? (
1170	        <div className="font-mono text-[11px] text-[var(--color-fg-muted)]">
1171	          working…
1172	        </div>
1173	      ) : null}
1174	    </div>
1175	  );
1176	}
1177	
1178	function ToolCallRow({ call }: { call: ToolCall }) {
1179	  const dot = call.status === "ok" ? "●" : call.status === "fail" ? "✕" : "◌";
1180	  const tone =
1181	    call.status === "ok"
1182	      ? "text-[var(--color-accent)]"
1183	      : call.status === "fail"
1184	        ? "text-red-400"
1185	        : "text-[var(--color-fg-muted)] animate-pulse";
1186	  return (
1187	    <div className="flex items-center gap-1.5 rounded border border-[var(--color-border-2)] bg-[var(--color-bg)]/50 px-1.5 py-0.5 font-mono text-[10.5px]">
1188	      <span className={cn("text-[10px]", tone)}>{dot}</span>
1189	      <span className="font-medium uppercase tracking-wide text-[var(--color-fg-dim)]">
1190	        {call.tool}
1191	      </span>
1192	      {call.url && (
1193	        <span className="flex-1 truncate text-[var(--color-fg-muted)]">
1194	          {call.url}
1195	        </span>
1196	      )}
1197	      {call.ms != null && (
1198	        <span className="text-[var(--color-fg-dim)]">{call.ms}ms</span>
1199	      )}
1200	      {call.chars != null && call.chars > 0 && (
