            <div className="flex shrink-0 gap-1 border-b border-[var(--color-border)] px-4 py-2 font-mono text-[11px]">
              {(["flow", "files"] as const).map((t) => (
                <button
                  key={t}
                  onClick={() => setTab(t)}
                  className={cn(
                    "rounded border px-2.5 py-1 uppercase tracking-wide transition-colors",
