              ))}
            </div>
          )}
          {(running || events.length > 0) && (!result || tab === "flow") && (
            <PipelineView
              events={events}
              cursor={cursor}
              followLive={followLive}
              running={running}
              compact={false}
              onCursor={(idx) => {
                setCursor(idx);
                setFollowLive(idx === events.length - 1);
              }}
              onFollowLive={() => {
                setFollowLive(true);
                setCursor(events.length - 1);
              }}
            />
          )}
          {result && tab === "files" && (
            <ResultView
              result={result}
              activeFile={activeFile}
              onActiveFile={setActiveFile}
            />
