      payload_hash: hash,
      received_at: new Date().toISOString(),
    },
    payload,
  };
}

async function buildTextRequest(
  source: string,
  kind: string,
  contentType: string,
  payloadUri: string,
  payload: string,
  propertyId: string,
  orgId: string,
): Promise<IngestRequest> {
  const hash = await sha256Hex(payload);
  return {
    envelope: {
      source,
      kind,
      org: orgId,
      property: propertyId,
      content_type: contentType,
      payload_uri: payloadUri,
      payload_hash: hash,
      received_at: new Date().toISOString(),
    },
    payload,
  };
}

const DEMO_SEEDS: DemoSeed[] = [
  {
    id: "stammdaten",
    label: "Stammdaten",
    detail: "Master data — building, units, owners, providers",
    build: (p, o) =>
      buildJsonRequest(
        "stammdaten",
        "stammdaten",
        "application/json",
        "demo/stammdaten.json",
        STAMMDATEN_PAYLOAD,
        p,
        o,
      ),
  },
  {
    id: "bank-csv",
    label: "Bank CSV",
    detail: "4 transactions (Sparkasse DTAUS-style)",
    build: (p, o) =>
      buildTextRequest(
        "bank",
        "bank-csv",
        "text/csv",
        "demo/bank.csv",
        BANK_CSV,
        p,
        o,
      ),
  },
];

export default function App() {
  const [propertyId, setPropertyId] = useState<PropertyId>(PROPERTIES[0]);
  const [orgId, setOrgIdState] = useState<string>(getOrgId());
  const [tab, setTab] = useState<Tab>("building");
  const [active, setActive] = useState<FactRead[]>([]);
  const [pending, setPending] = useState<PendingQuestion[]>([]);
  const [obligations, setObligations] = useState<FactRead[]>([]);
  const [buildingMd, setBuildingMd] = useState<string>("");
  const [sectionFilter, setSectionFilter] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [ingestBusy, setIngestBusy] = useState<string | null>(null);
  const [lastIngest, setLastIngest] = useState<string | null>(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [a, p, o, md] = await Promise.all([
        listActive(propertyId).then((r) => r.facts),
        listPending(propertyId).then((r) => r.questions),
        listObligations(propertyId).then((r) => r.facts),
        getBuildingMd(propertyId).catch(() => ""),
      ]);
      setActive(a);
      setPending(p);
      setObligations(o);
      setBuildingMd(md);
    } catch (e) {
      setError(String(e));
    } finally {
      setLoading(false);
    }
  }, [propertyId]);

  useEffect(() => {
    refresh();
  }, [refresh, orgId]);

  const sections = useMemo(() => {
    const counts = new Map<string, number>();
    for (const f of active) counts.set(f.section, (counts.get(f.section) ?? 0) + 1);
    return [...counts.entries()].sort(([a], [b]) => a.localeCompare(b));
  }, [active]);

  const filteredActive = useMemo(
    () =>
      sectionFilter ? active.filter((f) => f.section === sectionFilter) : active,
    [active, sectionFilter],
  );

  async function runSeed(seed: DemoSeed) {
    setIngestBusy(seed.id);
    setError(null);
    try {
      const body = await seed.build(propertyId, orgId);
      const resp = await postIngest(body);
      setLastIngest(
        `${seed.label}: env=${resp.envelope_id.slice(0, 16)} facts=${resp.fact_ids.length} gaps=${resp.gap_event_ids.length}`,
      );
      await refresh();
    } catch (e) {
      setError(String(e));
    } finally {
      setIngestBusy(null);
    }
  }

  function handleOrgChange(value: string) {
    setOrgId(value);
    setOrgIdState(value);
  }

  return (
    <div className="flex h-screen flex-col overflow-hidden bg-[var(--color-bg)] text-[var(--color-fg)]">
      <TopBar
        propertyId={propertyId}
        properties={[...PROPERTIES]}
        onPropertyChange={(v) => setPropertyId(v as PropertyId)}
        orgId={orgId}
        onOrgChange={handleOrgChange}
        onRefresh={refresh}
        loading={loading}
      />

      {error && (
        <div className="border-b border-red-500/40 bg-red-500/10 px-4 py-2 font-mono text-[12.5px] text-red-400">
          {error}
        </div>
      )}

      <div className="flex min-h-0 flex-1">
        <aside className="flex w-[240px] shrink-0 flex-col border-r border-[var(--color-border)] bg-[var(--color-bg)]/40">
          <div className="border-b border-[var(--color-border)] px-3 py-2 font-mono text-[11px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
            Sections ({sections.length})
          </div>
          <div className="min-h-0 flex-1 overflow-auto px-1.5 py-2">
            <button
              onClick={() => setSectionFilter(null)}
              className={cn(
                "mb-0.5 block w-full rounded px-2 py-1 text-left font-mono text-[12.5px]",
                sectionFilter === null
                  ? "bg-[var(--color-surface)] text-[var(--color-accent)]"
                  : "text-[var(--color-fg-muted)] hover:bg-[var(--color-surface)]/60 hover:text-[var(--color-fg)]",
              )}
            >
              all ({active.length})
            </button>
            {sections.map(([s, count]) => (
              <button
                key={s}
                onClick={() => setSectionFilter(s)}
                className={cn(
                  "mb-0.5 block w-full rounded px-2 py-1 text-left font-mono text-[12.5px]",
                  sectionFilter === s
                    ? "bg-[var(--color-surface)] text-[var(--color-accent)]"
                    : "text-[var(--color-fg-muted)] hover:bg-[var(--color-surface)]/60 hover:text-[var(--color-fg)]",
                )}
              >
                {s} <span className="text-[var(--color-fg-dim)]">({count})</span>
              </button>
            ))}
          </div>
        </aside>

        <main className="flex min-w-0 flex-1 flex-col">
          <div className="flex shrink-0 gap-1 border-b border-[var(--color-border)] px-4 py-2 font-mono text-[11px]">
            {TABS.map((t) => (
              <button
                key={t.key}
                onClick={() => setTab(t.key)}
                className={cn(
                  "rounded border px-2.5 py-1 uppercase tracking-wide transition-colors",
                  tab === t.key
                    ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
                    : "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)]",
                )}
              >
                {t.label}
                {t.key === "active" && ` (${filteredActive.length})`}
                {t.key === "pending" && ` (${pending.length})`}
                {t.key === "obligations" && ` (${obligations.length})`}
              </button>
            ))}
          </div>

          <div className="min-h-0 flex-1 overflow-auto">
            {tab === "building" && <BuildingView body={buildingMd} />}
            {tab === "active" && <FactsView facts={filteredActive} />}
            {tab === "pending" && <PendingView questions={pending} />}
            {tab === "obligations" && <FactsView facts={obligations} />}
          </div>
        </main>

        <aside className="flex w-[300px] shrink-0 flex-col border-l border-[var(--color-border)] bg-[var(--color-bg)]/40">
          <div className="border-b border-[var(--color-border)] px-3 py-2 font-mono text-[11px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
            Demo ingest
          </div>
          <div className="flex flex-col gap-2 px-3 py-3">
            {DEMO_SEEDS.map((s) => (
              <button
                key={s.id}
                onClick={() => runSeed(s)}
                disabled={ingestBusy !== null}
                className={cn(
                  "rounded-md border px-3 py-2 text-left transition-colors",
                  ingestBusy === s.id
                    ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
                    : "border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg)] hover:border-[var(--color-accent-dim)]",
                  ingestBusy !== null && ingestBusy !== s.id && "opacity-40",
                )}
              >
                <div className="font-mono text-[12.5px] font-medium">
                  {ingestBusy === s.id ? "POST…" : `▶ ${s.label}`}
                </div>
                <div className="mt-0.5 text-[11.5px] text-[var(--color-fg-muted)]">
