                {t.key === "pending" && ` (${pending.length})`}
                {t.key === "obligations" && ` (${obligations.length})`}
              </button>
            ))}
          </div>

          <div className="min-h-0 flex-1 overflow-auto">
            {tab === "building" && <BuildingView body={buildingMd} />}
            {tab === "active" && <FactsView facts={filteredActive} />}
            {tab === "pending" && <PendingView questions={pending} />}
            {tab === "obligations" && <FactsView facts={obligations} />}
          </div>
        </main>

        <aside className="flex w-[300px] shrink-0 flex-col border-l border-[var(--color-border)] bg-[var(--color-bg)]/40">
          <div className="border-b border-[var(--color-border)] px-3 py-2 font-mono text-[11px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
            Demo ingest
          </div>
          <div className="flex flex-col gap-2 px-3 py-3">
            {DEMO_SEEDS.map((s) => (
              <button
                key={s.id}
                onClick={() => runSeed(s)}
                disabled={ingestBusy !== null}
                className={cn(
                  "rounded-md border px-3 py-2 text-left transition-colors",
                  ingestBusy === s.id
                    ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
                    : "border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg)] hover:border-[var(--color-accent-dim)]",
                  ingestBusy !== null && ingestBusy !== s.id && "opacity-40",
                )}
              >
                <div className="font-mono text-[12.5px] font-medium">
                  {ingestBusy === s.id ? "POST…" : `▶ ${s.label}`}
                </div>
                <div className="mt-0.5 text-[11.5px] text-[var(--color-fg-muted)]">
                  {s.detail}
                </div>
              </button>
            ))}
            {lastIngest && (
              <div className="mt-1 rounded border border-[var(--color-border-2)] bg-[var(--color-bg)] px-2 py-1.5 font-mono text-[11px] text-[var(--color-fg-muted)]">
                {lastIngest}
              </div>
            )}
            <div className="mt-2 text-[11px] leading-relaxed text-[var(--color-fg-muted)]">
              Real <code>POST /api/v1/ingest</code> using <code>X-Org-ID: {orgId}</code>.
              Server runs deterministic skills, writes facts to DuckDB, re-renders building.md.
              Refreshes views on success.
            </div>
            <div className="mt-3 text-[11px] text-[var(--color-fg-dim)]">
              For richer LLM-extracted facts (emails, invoices, letters), run{" "}
              <code>uv run python scripts/ingest_fixture.py</code>.
            </div>
          </div>
        </aside>
      </div>
    </div>
  );
}

function BuildingView({ body }: { body: string }) {
  if (!body.trim()) {
    return (
      <div className="grid h-full place-items-center text-[13.5px] text-[var(--color-fg-muted)]">
        No building.md yet. Run a demo ingest →
      </div>
    );
  }
  return (
    <div className="prose prose-sm max-w-none px-6 py-6 dark:prose-invert prose-headings:mt-4 prose-headings:mb-2">
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{body}</ReactMarkdown>
    </div>
  );
}

function FactsView({ facts }: { facts: FactRead[] }) {
  if (facts.length === 0) {
    return (
      <div className="grid h-full place-items-center text-[13.5px] text-[var(--color-fg-muted)]">
        No facts.
      </div>
    );
  }
  const grouped = new Map<string, FactRead[]>();
  for (const f of facts) {
    const arr = grouped.get(f.section) ?? [];
    arr.push(f);
    grouped.set(f.section, arr);
  }
  return (
    <div className="px-4 py-4">
      {[...grouped.entries()]
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([section, items]) => (
          <section key={section} className="mb-6">
            <h2 className="mb-2 font-mono text-[12px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
              {section} <span className="text-[var(--color-fg-dim)]">({items.length})</span>
            </h2>
            <div className="space-y-1.5">
              {items.map((f) => (
                <FactRow key={f.fact_id} fact={f} />
              ))}
            </div>
          </section>
        ))}
    </div>
  );
}

function FactRow({ fact }: { fact: FactRead }) {
  return (
    <div className="rounded border border-[var(--color-border-2)] bg-[var(--color-surface)]/40 px-3 py-2">
      <div className="flex items-baseline justify-between gap-3">
        <code className="font-mono text-[12.5px] text-[var(--color-accent)]">
          {fact.key}
        </code>
        <span className="font-mono text-[10.5px] uppercase tracking-wide text-[var(--color-fg-dim)]">
          {fact.status} · conf {fact.confidence.toFixed(2)}
        </span>
      </div>
      <pre className="mt-1 overflow-auto whitespace-pre-wrap break-words font-mono text-[11.5px] leading-snug text-[var(--color-fg)]">
        {formatValue(fact.value)}
      </pre>
      {(fact.citation.source_kind || fact.citation.source_id) && (
        <div className="mt-1 font-mono text-[10.5px] text-[var(--color-fg-dim)]">
          source: {fact.citation.source_kind}:{fact.citation.source_id}
          {fact.citation.locator ? ` · ${fact.citation.locator}` : ""}
        </div>
      )}
    </div>
  );
}

function PendingView({ questions }: { questions: PendingQuestion[] }) {
  if (questions.length === 0) {
    return (
      <div className="grid h-full place-items-center text-[13.5px] text-[var(--color-fg-muted)]">
        No pending questions.
      </div>
    );
  }
  return (
    <div className="space-y-1.5 px-4 py-4">
      {questions.map((q) => (
        <div
          key={q.fact_id}
          className="rounded border border-[var(--color-border-2)] bg-[var(--color-surface)]/40 px-3 py-2"
        >
          <div className="flex items-baseline justify-between gap-3">
            <code className="font-mono text-[12.5px] text-[var(--color-accent)]">
              {q.section} / {q.key}
            </code>
            <span className="font-mono text-[10.5px] uppercase tracking-wide text-[var(--color-fg-dim)]">
              conf {q.confidence.toFixed(2)}
            </span>
          </div>
          <pre className="mt-1 overflow-auto whitespace-pre-wrap break-words font-mono text-[11.5px] leading-snug text-[var(--color-fg)]">
            {formatValue(q.value)}
          </pre>
        </div>
      ))}
    </div>
  );
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value;
  return JSON.stringify(value, null, 2);
}

