import { Building2, Moon, RefreshCw, Sun } from "lucide-react";
import { useEffect, useState } from "react";
import { cn } from "../lib/cn";

type Props = {
  propertyId: string;
  properties: string[];
  onPropertyChange: (value: string) => void;
  orgId: string;
  onOrgChange: (value: string) => void;
  onRefresh: () => void;
  loading: boolean;
};

export function TopBar({
  propertyId,
  properties,
  onPropertyChange,
  orgId,
  onOrgChange,
  onRefresh,
  loading,
}: Props) {
  const [theme, setTheme] = useState<"dark" | "light">(() => {
    if (typeof window === "undefined") return "dark";
    const stored = window.localStorage.getItem("theme");
    if (stored === "light" || stored === "dark") return stored;
    return window.matchMedia("(prefers-color-scheme: light)").matches
      ? "light"
      : "dark";
  });

  useEffect(() => {
    const root = document.documentElement;
    root.classList.toggle("dark", theme === "dark");
    root.classList.toggle("light", theme === "light");
    window.localStorage.setItem("theme", theme);
  }, [theme]);

  return (
    <header className="glass sticky top-0 z-40 flex h-12 shrink-0 items-center justify-between gap-4 border-b border-[var(--color-border)] px-4">
      <div className="flex items-center gap-3">
        <div className="grid h-6 w-6 place-items-center rounded-md bg-[var(--color-accent)] text-[#0b0b0a]">
          <Building2 className="h-3.5 w-3.5" strokeWidth={2.5} />
        </div>
        <span className="font-display text-[15px] font-medium tracking-tight text-[var(--color-ink-50)]">
          PropContext
        </span>
        <span className="hidden text-[11px] uppercase tracking-[0.18em] text-[var(--color-fg-muted)] sm:inline">
          Facts
        </span>
      </div>

      <div className="flex items-center gap-2">
        <Field label="org">
          <input
            value={orgId}
            onChange={(e) => onOrgChange(e.target.value)}
            spellCheck={false}
            className="h-7 w-[150px] rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)] px-2 font-mono text-[12px] text-[var(--color-fg)] outline-none transition-colors focus:border-[var(--color-accent)]"
          />
        </Field>
        <Field label="property">
          <select
            value={propertyId}
            onChange={(e) => onPropertyChange(e.target.value)}
            className="h-7 cursor-pointer rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)] px-2 font-mono text-[12px] text-[var(--color-fg)] outline-none transition-colors hover:border-[var(--color-accent-dim)]"
          >
            {properties.map((p) => (
              <option key={p} value={p}>
                {p}
              </option>
            ))}
          </select>
        </Field>
        <button
          onClick={onRefresh}
          disabled={loading}
          aria-label="Refresh"
          title="Refresh"
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border transition-colors",
            "border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg-muted)]",
            "hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
            loading && "opacity-50",
          )}
        >
          <RefreshCw className={cn("h-3.5 w-3.5", loading && "animate-spin")} />
        </button>
        <button
          onClick={() => setTheme((t) => (t === "dark" ? "light" : "dark"))}
          aria-label="Toggle theme"
          className="grid h-7 w-7 place-items-center rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg-muted)] transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]"
        >
          {theme === "dark" ? (
            <Sun className="h-3.5 w-3.5" />
          ) : (
            <Moon className="h-3.5 w-3.5" />
          )}
        </button>
      </div>
    </header>
  );
}

function Field({
  label,
  children,
}: {
  label: string;
  children: React.ReactNode;
}) {
  return (
    <label className="flex items-center gap-1.5">
      <span className="font-mono text-[10.5px] uppercase tracking-[0.18em] text-[var(--color-fg-dim)]">
        {label}
      </span>
      {children}
    </label>
  );
}

