118	export async function runSimIngestStream(
119	  body: {
120	    day: number;
121	    kind: "email" | "invoice" | "bank";
122	    id: string;
123	    mode: "isolated" | "live";
124	    property_id?: string;
125	  },
126	  handlers: {
127	    onStage: (ev: SimStageEvent) => void;
128	    onResponse: (resp: SimIngestResponse) => void;
129	    onError: (err: { status: number; detail: string }) => void;
130	  },
131	  signal?: AbortSignal,
132	): Promise<void> {
133	  const r = await fetch(`${base}/sim/ingest/stream`, {
134	    method: "POST",
135	    headers: { "content-type": "application/json" },
136	    body: JSON.stringify(body),
137	    signal,
138	  });
139	  if (!r.ok || !r.body) {
140	    const detail = await r.text().catch(() => "");
141	    throw new Error(`sim/ingest/stream ${r.status}: ${detail}`);
142	  }
143	  const reader = r.body.getReader();
144	  const decoder = new TextDecoder();
145	  let buf = "";
146	  while (true) {
147	    const { value, done } = await reader.read();
148	    if (done) break;
149	    buf += decoder.decode(value, { stream: true });
150	    let idx;
151	    while ((idx = buf.indexOf("\n\n")) !== -1) {
152	      const block = buf.slice(0, idx);
153	      buf = buf.slice(idx + 2);
154	      const dataLine = block
155	        .split("\n")
156	        .find((l) => l.startsWith("data:"));
157	      if (!dataLine) continue;
158	      const json = dataLine.slice(5).trim();
159	      try {
160	        const parsed = JSON.parse(json) as
161	          | { stage: string; data: Record<string, unknown> }
162	          | Record<string, unknown>;
163	        const stage = (parsed as { stage?: string }).stage;
164	        if (stage === "response") {
165	          handlers.onResponse(
166	            (parsed as { data: SimIngestResponse }).data,
167	          );
168	        } else if (stage === "error") {
169	          handlers.onError(
170	            (parsed as { data: { status: number; detail: string } }).data,
171	          );
172	        } else if (typeof stage === "string") {
173	          handlers.onStage(parsed as SimStageEvent);
174	        }
175	      } catch {
176	        // ignore malformed
177	      }
178	    }
179	  }
180	}
